const stdout = items[0].json.stdout || "";

const data = {};
for (const line of stdout.split("\n")) {
  const index = line.indexOf("=");
  if (index === -1) continue;

  const key = line.slice(0, index).trim();
  const value = line.slice(index + 1).trim();
  data[key] = value;
}

const usbMounted = Number(data.USB_MOUNT || 0) > 0;
const hasLatestBackup = Boolean(data.LATEST_BACKUP);
const backupsLast24h = Number(data.BACKUP_COUNT_24H || 0);

const backupOk = usbMounted && hasLatestBackup && backupsLast24h > 0;

const lines = [];

lines.push("💾 **Proxmox USB Backup Verification**");
lines.push("");
lines.push(`🕒 Time: ${new Date().toLocaleString("en-US", { timeZone: "America/Santo_Domingo" })}`);
lines.push(`🖥️ Host: ${data.HOST || "proxmox"}`);
lines.push("");

lines.push(backupOk ? "✅ **Proxmox backup looks good**" : "🚨 **Proxmox backup needs attention**");
lines.push("");

lines.push(`${usbMounted ? "✅" : "🚨"} USB drive mounted`);
lines.push(`${hasLatestBackup ? "✅" : "🚨"} Latest backup found`);
lines.push(`${backupsLast24h > 0 ? "✅" : "🚨"} Backups in last 24h: ${backupsLast24h}`);

lines.push("");
lines.push(`💽 USB usage: ${data.USB_DISK || "unknown"}`);

lines.push("");
lines.push("**Latest backup**");
lines.push("```");
lines.push(data.LATEST_BACKUP_TIME || data.LATEST_BACKUP || "missing");
lines.push("```");

return [
  {
    json: {
      content: lines.join("\n"),
      backupOk
    }
  }
];
